func solve(s: String): String {
    var result = ""
    for char in s {
        if char.isLowercase {
            result += String(char)
        } else if char == "*" {
            if !result.isEmpty {
                result.removeLast()
            }
        } else if char == "#" {
            result += result
        } else if char == "%" {
            result = String(result.reversed())
        }
    }
    return result
}
